import java.io.*;class Main{static int[] solve(int[][] positions){int n=positions.length;int[] heights=new int[n];int[] answer=new int[n];int best=0;for(int i=0;i<n;i++){int left=positions[i][0],size=positions[i][1],right=left+size,base=0;for(int j=0;j<i;j++){int otherLeft=positions[j][0],otherRight=otherLeft+positions[j][1];if(left<otherRight&&otherLeft<right)base=Math.max(base,heights[j]);}heights[i]=base+size;best=Math.max(best,heights[i]);answer[i]=best;}return answer;}static String fmt(int[] a){StringBuilder out=new StringBuilder("[");for(int i=0;i<a.length;i++){if(i>0)out.append(",");out.append(a[i]);}return out.append("]").toString();}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]);int[][] positions=new int[n][2];for(int i=0;i<n;i++){positions[i][0]=Integer.parseInt(d[idx++]);positions[i][1]=Integer.parseInt(d[idx++]);}if(tc>0)out.append("\n\n");out.append(fmt(solve(positions)));}System.out.print(out);}}
